#include <bits/stdc++.h>
using namespace std;
const int M=1000005;
int n,m,l,r,prime[M],cnt;
bool flag[M];
void prepare()
{ 
	for(int i=2;i<=m;i++)
	{
		if(!flag[i]) prime[++cnt]=i;
		for(int j=1;j<=cnt&&(i*prime[j])<=m;j++)
		{
			flag[i*prime[j]]=1;
			if(i%prime[j]==0) break;
		}
	}
}
int main()
{
	cin>>n>>m;
	prepare();
	while(n--)
	{
		cin>>l>>r;
		if(l<1||r>m)
		{
			cout<<"Crossing the line\n";
			continue;
		}
		int t=(upper_bound(prime+1,prime+1+cnt,r)-lower_bound(prime+1,prime+1+cnt,l));
		cout<<t<<'\n'; 
	}
	return 0;
}
